import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.println("Enter your name: ");
            String name = br.readLine();

            // Properly escape user input before including it in the HTML response
            String escapedName = Encode.forHtml(name);
            String htmlResponse = "<html><body><h1>Welcome, " + escapedName + "!</h1></body></html>";

            System.out.println(htmlResponse);
        } catch (IOException e) {
            System.err.println("An error occurred while reading user input.");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
